const updateStepRunDecision = `-- name: UpdateStepRunDecision :one
UPDATE workflow_step_run SET
    decision = $2,
    decision_comment = $3,
    redirect_to_step = $4,
    status = CASE
        WHEN $2 = 'approved' THEN 'completed'
        WHEN $2 = 'rejected' THEN 'rejected'
        WHEN $2 = 'stopped' THEN 'failed'
        WHEN $2 = 'redirect' THEN 'completed'
        ELSE status
    END,
    completed_at = now()
WHERE id = $1 AND step_type IN ('approval', 'review') AND status = 'running'
RETURNING id, workflow_run_id, step_index, step_type, status, agent_task_id, reviewer_id, decision, decision_comment, started_at, completed_at, created_at, redirect_to_step
`

type UpdateStepRunDecisionParams struct {
	ID              pgtype.UUID `json:"id"`
	Decision        pgtype.Text `json:"decision"`
	DecisionComment pgtype.Text `json:"decision_comment"`
	RedirectToStep  pgtype.Int4 `json:"redirect_to_step"`
}

func (q *Queries) UpdateStepRunDecision(ctx context.Context, arg UpdateStepRunDecisionParams) (WorkflowStepRun, error) {
	row := q.db.QueryRow(ctx, updateStepRunDecision,
		arg.ID,
		arg.Decision,
		arg.DecisionComment,
		arg.RedirectToStep,
	)
	var i WorkflowStepRun
	err := row.Scan(
		&i.ID,
		&i.WorkflowRunID,
		&i.StepIndex,
		&i.StepType,
		&i.Status,
		&i.AgentTaskID,
		&i.ReviewerID,
		&i.Decision,
		&i.DecisionComment,
		&i.StartedAt,
		&i.CompletedAt,
		&i.CreatedAt,
		&i.RedirectToStep,
	)
	return i, err
}

